{
  "verses": [
    {
      "n": 10,
      "column": "left",
      "text": "Wiꞥſch Walgs irr eekſch\nSemmes apſlehts / un wiꞥſch\nSlaſds us to Zeltu.\n"
    },
    {
      "n": 11,
      "column": "left",
      "text": "Wiſſapkaht wiꞥſu Bai-\nibas iſtruhzinajahs/ un ſtaipibs\nwiꞥſu pa Kahju Galleem.\n"
    },
    {
      "n": 12,
      "column": "left",
      "text": "Wiꞥſch Spehks nenihks\nBaddá/ un Bohja-Eefchana\nihs gattawa pee wiꞥſu Sah-\neeem.\n"
    },
    {
      "n": 13,
      "column": "left",
      "text": "Wiꞥſu Ahdas Stipru-\nnn ehdihs/ wiꞥſu Spehku eh-\nihs breeſiniga Nahwe.\n"
    },
    {
      "n": 14,
      "column": "left",
      "text": "Wiꞥſu Zerriha taps no\nwiꞥſu Dsihwokta atxenta/ un\nas wiꞥſu dsenn pee ta Kehuika\nahs Iſtruhzinachanas.\n"
    },
    {
      "n": 15,
      "column": "left",
      "text": "Wiꞥſu Dsihwokli nenee-\na ne buhs/ wiꞥſu Mahja taps\nr Sehru apkaſita.\n"
    },
    {
      "n": 16,
      "column": "left",
      "text": "No Appakchas wiꞥſu\nSaknes ſakaltihs/ un no aug-\nchenes taps wiꞥſu Augti no-\nreesti.\n"
    },
    {
      "n": 17,
      "column": "left",
      "text": "Wiꞥſu Peeminneſchana\nsnihs no Semmes/ un wiꞥ-\nkam ne buhs ne kahda Sława\nis Eelabm.\n"
    },
    {
      "n": 18,
      "column": "left",
      "text": "Wiꞥſch taps no Gaifmas\neekſch Tumfıbas iſſtuunts/ un\nno Semmes Wirſus iſwajahts.\n"
    },
    {
      "n": 19,
      "column": "left",
      "text": "Wiꞥſam ne buhs nei\nBehrni/ nei Behrnu Behrni fa-\nwôs Laudıs/ un ne weens wiꞥ-\nna Weetâs taps atlizzinahts.\n"
    },
    {
      "n": 20,
      "column": "left",
      "text": "Wiꞥſu Pehznahkamee\npahr wiꞥſu Deenu isbeedefces/\n"
    },
    {
      "n": 21,
      "column": "right",
      "text": "Teeſcham/ tahdi irr ta\nNetaisına Dsihwokti/ un ſebahda\nirr ta Weeta to/ kas to STIP-\nRU DEEWU ne atſibſt.\n"
    },
    {
      "n": 1,
      "column": "right",
      "text": "un teem Preeſchajeem Bailiba\nusees.\n"
    },
    {
      "n": 2,
      "column": "right",
      "text": "Un fuhoſs kaḣds nizzinahts un atſlahts wiꞥſch\neſkus eekſch faraṣ nenopelnitas Zeefchanaṣ:\n"
    },
    {
      "n": 6,
      "column": "right",
      "text": "Iſteiz pehdigi/ ka wiꞥſch to Augſcham-\nzelfchanu ar ſipru Tizzihu zerre/ kurraṣ\nwiꞥſch ari jirdigi eepreezinajahṣ: 25.\n"
    },
    {
      "n": 1,
      "column": "right",
      "text": "Et Jiahs atbildeja/ un\nſazzija:\n"
    },
    {
      "n": 2,
      "column": "right",
      "text": "Zik ilgi gribbat\niuhs mannu Divehteli apbehdi-\nnaht/ un manni ar Wahrdeem\ninhziht ?\n"
    },
    {
      "n": 3,
      "column": "right",
      "text": "Juhs gann deſmitſkahrt\nmanni effat Kaunaſikkufchi/ juhs\npaſchi ne kaunatees manni ta\nwaiaht.\n"
    },
    {
      "n": 4,
      "column": "right",
      "text": "Un pateefi/ jepſchu es buh-\ntchu maldtjees/ un Maldichana\npee mannim wehl buhtu.\n"
    },
    {
      "n": 5,
      "column": "right",
      "text": "Bij tad jums prett man-\nni zelteeṣ/ un manto par Kaunu\npahrniest?\n"
    },
    {
      "n": 6,
      "column": "right",
      "text": "Nemmeet jelle wehra/ ka\nDeews manni irr pawehrtijs/\nun manni ar ſawu Tihkli ap-\nkaht apwaldſinaje.\n"
    },
    {
      "n": 7,
      "column": "right",
      "text": "Reds/ es brehzu pahr War-\nras-Darbu/ bet man ne tohp at-\nbildehts/ es fauzu/ bet Teefas\nnewaid.\n"
    },
    {
      "n": 8,
      "column": "right",
      "text": "Wiꞥſch irr mannu Zettu\naismuhrejs/ ka es ne warru\npahrſtaigaht/ un pahr man-\nnahm\n"
    }
  ],
  "confidence": "high",
